proof_block:
// Destructure both candidate results so we can name their pieces.
let (ok1, event_results1_g, ios1_g) = r1;
let (ok2, event_results2_g, ios2_g) = r2;
let er1 = event_results1_g@;
let er2 = event_results2_g@;
let io1 = ios1_g@;
let io2 = ios2_g@;

// The previous attempt unconditionally asserted facts from the ensures
// clause, but the ensures is `(R1_ensures && R2_ensures) ==> det_equal`,
// so those conjuncts are only valid *under the antecedent*. Verus
// rejected `assert(post1_self_.invariants(...))` because the fact is
// hypothetical, not given. We fix that by wrapping the proof body in
// `if <antecedent>`: inside the branch every ensures conjunct is a fact,
// outside the branch `P ==> det_equal` is vacuous. The branch then
// supplies trigger hints for the two `forall` quantifiers in
// `well_typed_events` and for the `event_seq` decomposition.
if ({
    &&& post1_self_.invariants(&post1_netc.my_end_point())
    &&& post1_self_@.constants == pre_self_@.constants
    &&& ok1 == post1_netc.ok()
    &&& (ok1 || er1.sends.len() > 0) ==> post1_netc.history() == old_netc_history + er1.ios
    &&& er1.ios == er1.event_seq()
    &&& er1.well_typed_events()
    &&& ok1 ==> {
        &&& receive_packet_next(pre_self_@, post1_self_@, io1)
        &&& raw_io_consistent_with_spec_io(er1.ios, io1)
        &&& no_invalid_sends(io1)
    }
}) && ({
    &&& post2_self_.invariants(&post2_netc.my_end_point())
    &&& post2_self_@.constants == pre_self_@.constants
    &&& ok2 == post2_netc.ok()
    &&& (ok2 || er2.sends.len() > 0) ==> post2_netc.history() == old_netc_history + er2.ios
    &&& er2.ios == er2.event_seq()
    &&& er2.well_typed_events()
    &&& ok2 ==> {
        &&& receive_packet_next(pre_self_@, post2_self_@, io2)
        &&& raw_io_consistent_with_spec_io(er2.ios, io2)
        &&& no_invalid_sends(io2)
    }
}) {
    // Re-surface each conjunct of R1's ensures using the destructured names.
    // These pull the facts out of the matched-tuple form into a shape z3
    // can match with the analogous r2 facts.
    assert(post1_self_.invariants(&post1_netc.my_end_point()));
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(ok1 == post1_netc.ok());
    assert((ok1 || er1.sends.len() > 0)
        ==> post1_netc.history() == old_netc_history + er1.ios);
    assert(er1.ios == er1.event_seq());
    assert(er1.well_typed_events());
    assert(ok1 ==> receive_packet_next(pre_self_@, post1_self_@, io1));
    assert(ok1 ==> raw_io_consistent_with_spec_io(er1.ios, io1));
    assert(ok1 ==> no_invalid_sends(io1));

    // Mirror lift for r2.
    assert(post2_self_.invariants(&post2_netc.my_end_point()));
    assert(post2_self_@.constants == pre_self_@.constants);
    assert(ok2 == post2_netc.ok());
    assert((ok2 || er2.sends.len() > 0)
        ==> post2_netc.history() == old_netc_history + er2.ios);
    assert(er2.ios == er2.event_seq());
    assert(er2.well_typed_events());
    assert(ok2 ==> receive_packet_next(pre_self_@, post2_self_@, io2));
    assert(ok2 ==> raw_io_consistent_with_spec_io(er2.ios, io2));
    assert(ok2 ==> no_invalid_sends(io2));

    // event_seq() decomposition: ios = recvs + clocks + sends. Using Seq's
    // extensional equality (`=~=`) lets z3 lift pointwise reasoning.
    assert(er1.ios =~= er1.recvs + er1.clocks + er1.sends);
    assert(er2.ios =~= er2.recvs + er2.clocks + er2.sends);

    // Instantiate the per-index well_typed_events foralls on both runs so
    // z3 has matching ground instances for any index it picks.
    assert forall|i: int| 0 <= i < er1.recvs.len() implies #[trigger] er1.recvs[i] is Receive by {
        assert(er1.well_typed_events());
    };
    assert forall|i: int| 0 <= i < er2.recvs.len() implies #[trigger] er2.recvs[i] is Receive by {
        assert(er2.well_typed_events());
    };
    assert forall|i: int| 0 <= i < er1.sends.len() implies #[trigger] er1.sends[i] is Send by {
        assert(er1.well_typed_events());
    };
    assert forall|i: int| 0 <= i < er2.sends.len() implies #[trigger] er2.sends[i] is Send by {
        assert(er2.well_typed_events());
    };
    assert forall|i: int| 0 <= i < er1.clocks.len()
        implies (#[trigger] er1.clocks[i] is ReadClock || er1.clocks[i] is TimeoutReceive)
    by {
        assert(er1.well_typed_events());
    };
    assert forall|i: int| 0 <= i < er2.clocks.len()
        implies (#[trigger] er2.clocks[i] is ReadClock || er2.clocks[i] is TimeoutReceive)
    by {
        assert(er2.well_typed_events());
    };

    // The two history equalities (when applicable) jointly force the ios
    // sequences to agree by cancellation on the common `old_netc_history`
    // prefix. Surface that consequence as an aid.
    if (ok1 || er1.sends.len() > 0) && (ok2 || er2.sends.len() > 0) {
        assert(post1_netc.history() == old_netc_history + er1.ios);
        assert(post2_netc.history() == old_netc_history + er2.ios);
    }
}
